def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=np.float64)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0.0
        for j in range(1, 15):
            weight = np.exp(-j / 5) / (j ** 1.3)
            term = (ratio ** j) * weight
            if j % 3 == 0:
                term *= 1.15
            elif j % 2 == 0:
                term *= 0.85
            else:
                term *= 1.05
            score += term
        remaining = capacity - item
        if remaining < 0.05 * capacity:
            score *= 2.5
            for k in range(1, 4):
                if i - k >= 0:
                    neighbor_cap = bins[i - k]
                    if neighbor_cap > capacity:
                        score *= 1.1
                    else:
                        score *= 0.95
        elif remaining < 0.2 * capacity:
            score *= 1.4
            if i + 1 < n and bins[i + 1] < capacity:
                score *= 0.9
        else:
            for k in range(1, 5):
                if remaining > k * 0.15 * capacity:
                    score *= 0.92 ** k
        if item > 0.6 * capacity:
            score += np.log1p(item) * 0.7
            if i % 2 == 0:
                score *= 1.05
            else:
                score *= 0.95
        if i > 0 and i < n - 1:
            left = bins[i - 1]
            right = bins[i + 1]
            if left < capacity and right < capacity:
                score *= 1.2
            elif left > capacity and right > capacity:
                score *= 0.85
            else:
                score *= 1.0 + 0.05 * np.sin(i + item)
        if score < 0.05:
            score += 0.02 * (capacity - item) + 0.01 * i
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1.0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(n):
        if priorities[i] == np.inf or np.isnan(priorities[i]):
            priorities[i] = max_priority * 3
    for i in range(n):
        if priorities[i] < 0.15:
            priorities[i] += 0.1 * np.cos(i * 0.5 + item)
    return priorities
